	SET
 		APP_CD_NM = #{appCdNm, jdbcType = VARCHAR}		
    		,ALIGN_ORDER_NO = #{alignOrderNo, jdbcType = NUMERIC}		
  		,APP_CD_DESC = #{appCdDesc, jdbcType = VARCHAR}		
   	WHERE APP_CD = #{appCd, jdbcType = VARCHAR}
	
		AND   PARENT_APP_CD = #{parentAppCd, jdbcType = VARCHAR}
	
	AND   LV_CD = #{lvCd, jdbcType = VARCHAR}

